const now = new Date();
const tokyoTime = now.toLocaleString('en-US', { timeZone: 'Asia/Tokyo', weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', hour: 'numeric', minute: 'numeric', second: 'numeric', hour12: true });
const utcTime = now.toLocaleString('en-US', { timeZone: 'UTC', weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', hour: 'numeric', minute: 'numeric', second: 'numeric', hour12: true });
const offset = now.toLocaleString('en-US', { timeZone: 'Asia/Tokyo', timeZoneName: 'short' });
return { tokyoTime, utcTime, offset };
